1	// basics task: baselining — the per-repo SELF-REFRESH (per-project-scheduling
2	// DESIGN §6, decision §11.7). Under the old fleet planner this was one leg of a
3	// central pass over every member; here every repo baselines ITSELF from its own
4	// scheduler, converging its own `.claudinite/shared/` mount to the current canon
5	// head, applying the migration notes that landed since its stamp, and advancing
6	// the stamp — one transactional commit on the `claudinite/maintenance` PR
7	// (worker: task.md). No cross-repo reach: the read-only canon checkout the
8	// worker vendors from already rides in the executor session's sources (DESIGN §5).
9	//
10	// Self-contained (imports nothing) so the scheduler, executor, and a human all
11	// load it standalone — the whole contract lives in this default export.
12	
13	export default {
14	  id: 'baselining',
15	  frequency: 'daily-2h',           // the 02:00 slot — a repo's mount is converged before anything reads it (DESIGN §2)
16	  precondition_signals: ['stamp', 'sharedMount'],
17	  agent_model: 'sonnet',                 // the bootstrap/alignment merges into settings.json without clobbering — judgment
18	  expected_outcome: 'merged-pr',            // lands on the maintenance PR; arms auto-merge where member config allows
19	  agent_instructions: 'task.md',
20	  agent_execution_timeout: 1800,            // generous: a migration-note night can be substantial; the common night is mechanical
21	
22	  // Run when this repo's vendored mount is behind the canon, or a declared pack's
23	  // vendored files moved. PURE over the collected signals — no probes here; the
24	  // worker does the converge/apply/stamp work.
25	  precondition(signals) {
26	    const stamp = signals.stamp ?? {};
27	    const changed = signals.sharedMount?.changedPacks ?? [];
28	
29	    // No stamp → no vendored mount to refresh (the canon's own repo, or a
30	    // pre-adoption repo): baselining self-skips, exactly as the old fleet pass
31	    // skipped home. `ref` null means the same — nothing to converge against.
32	    if (!stamp.ref && stamp.ageDays === null) {
33	      return { run: false, reason: 'no vendored mount (no stamp) — nothing to self-refresh' };
34	    }
35	
36	    // Primary trigger: the stamp is behind the canon head. `canonHead` is only
37	    // populated when the Action could read the canon; when it is null we cannot
38	    // diff, so fall back to stamp AGE — a mount that hasn't refreshed in over a
39	    // day is due regardless (DESIGN §6, §3.3: "stamp-age fallback when the canon
40	    // isn't readable from the Action").
41	    const behindCanon = stamp.canonHead != null && stamp.canonHead !== stamp.ref;
42	    const staleByAge = stamp.canonHead == null && typeof stamp.ageDays === 'number' && stamp.ageDays > 1;
43	
44	    // A declared pack's vendored files changed in the window (a member-side edit
45	    // to the read-only mount, or an already-landed refresh commit) — converge it
46	    // back to the canon snapshot so drift never accumulates.
47	    const mountMoved = changed.length > 0;
48	
49	    if (behindCanon) {
50	      return { run: true, reason: `mount at ${String(stamp.ref).slice(0, 7)} is behind canon head ${String(stamp.canonHead).slice(0, 7)}`, context: [`Converge \`.claudinite/shared/\` to canon head ${stamp.canonHead} and apply any migration notes dated on/after the stamp (${stamp.updated}).`] };
51	    }
52	    if (staleByAge) {
53	      return { run: true, reason: `canon head unreadable — stamp is ${stamp.ageDays.toFixed(1)}d old (age fallback)`, context: [`Canon head was not readable from the scheduler; refresh from the canon checkout in session and apply notes dated on/after the stamp (${stamp.updated}).`] };
54	    }
55	    if (mountMoved) {
56	      return { run: true, reason: `vendored files changed for declared pack(s): ${changed.join(', ')}`, context: [`Re-converge these packs' vendored files to the canon snapshot: ${changed.join(', ')}.`] };
57	    }
58	    return { run: false, reason: 'mount is at canon head and no vendored files moved' };
59	  },
60	};
61

