1	// The pre-agent preprocessing stage (agent-preprocessing DESIGN §3). The
2	// scheduler runs a task's declared `agent_preprocessing` command as a SUBPROCESS
3	// before any agent starts — deterministic code work, Action-side, over the one
4	// sanctioned non-MCP surface (the Action GITHUB_TOKEN, inherited in `env`).
5	//
6	// The subprocess is the scheduler's child, so its `agent_preprocessing_timeout`
7	// is a HARD kill: a manual timer SIGKILLs an overrun and the run is reported
8	// failed. Its cwd is the TASK directory, so a declared `node worker.mjs` resolves
9	// to the script beside task.mjs (the containment the contract enforces); the repo
10	// root and slot context are handed in via CLAUDINITE_* env so the worker can act
11	// on the whole repo. Nothing the subprocess prints is threaded into the agent —
12	// preprocessing communicates only through the repository (DESIGN §3).
13	
14	import { spawn } from 'node:child_process';
15	
16	// Run `command` as a subprocess bounded by `timeoutSeconds`. Resolves (never
17	// rejects) with { ok, timedOut, code, signal, stdout, stderr }: `ok` is a clean
18	// zero exit that did not time out. `taskDir` is the cwd; `env` is the full
19	// environment the child inherits (the caller injects GITHUB_TOKEN + CLAUDINITE_*).
20	export function runPreprocessing(command, { taskDir, env, timeoutSeconds }) {
21	  return new Promise((resolve) => {
22	    const child = spawn(command, { cwd: taskDir, env, shell: true });
23	    let stdout = '';
24	    let stderr = '';
25	    let timedOut = false;
26	    const timer = setTimeout(() => {
27	      timedOut = true;
28	      child.kill('SIGKILL'); // the hard kill — no grace period past the declared bound
29	    }, timeoutSeconds * 1000);
30	
31	    child.stdout?.on('data', (d) => { stdout += d; });
32	    child.stderr?.on('data', (d) => { stderr += d; });
33	    // A spawn error (command not found, etc.) is a failure, not a throw.
34	    child.on('error', (e) => {
35	      clearTimeout(timer);
36	      resolve({ ok: false, timedOut, code: null, signal: null, stdout, stderr: `${stderr}${e.message}` });
37	    });
38	    child.on('close', (code, signal) => {
39	      clearTimeout(timer);
40	      resolve({ ok: code === 0 && !timedOut, timedOut, code, signal, stdout, stderr });
41	    });
42	  });
43	}
44	
45	// A one-line reason for the job summary / an issue comment when preprocessing
46	// fails — distinguishing a timeout kill from a non-zero exit.
47	export function preprocessingFailure(result) {
48	  if (result.timedOut) return 'preprocessing exceeded its agent_preprocessing_timeout and was killed';
49	  if (result.code !== null) return `preprocessing exited ${result.code}`;
50	  return `preprocessing could not run: ${result.stderr.trim().split('\n').pop() || 'unknown error'}`;
51	}
52

