1	// The scheduler entrypoint's orchestration core (per-project-scheduling DESIGN
2	// §3). The vendored hourly Action runs this: decide due slots from the run
3	// ledger, discover active tasks, collect only the signals the due tasks declare,
4	// run each precondition, and either dispatch agent work as a `ready-for-agent`
5	// issue or (for `agent_model: none`) run the worker inline.
6	//
7	// This module is the DECISION core, kept injectable so it tests with fakes: the
8	// GitHub I/O (the Actions run-ledger read for `lastSuccess`, the signal
9	// collectors, the issue search/create) is supplied by the thin CLI shell around
10	// `planRun`. The "should this run" verdict is always code here — never the
11	// shell's judgment (the same split the fleet planner uses).
12	
13	import { pathToFileURL } from 'node:url';
14	import { dueSlots } from './slots.mjs';
15	import { planDispatch, dispatchTitle, dispatchBody, DISPATCH_PREFIX, READY_LABEL, NEEDS_HUMAN_LABEL, SCHEDULER_LABELS } from './dispatch.mjs';
16	import { isAgentless } from './model-map.mjs';
17	import { runPreprocessing, preprocessingFailure } from './preprocess.mjs';
18	
19	// The due tasks, each paired with the slot it runs under. Union the discovered
20	// tasks' frequencies, ask slots which are due (run-ledger math), then map due
21	// frequencies back to their tasks. A task whose frequency isn't due drops out.
22	export function computeDueTaskSlots(tasks, schedule, now, lastSuccess) {
23	  const frequencies = [...new Set(tasks.map((t) => t.decl.frequency))];
24	  const due = new Map(dueSlots(frequencies, schedule, now, lastSuccess).map((d) => [d.frequency, d]));
25	  const out = [];
26	  for (const task of tasks) {
27	    const slot = due.get(task.decl.frequency);
28	    if (slot) out.push({ task, slotId: slot.slotId, slotTime: slot.slotTime });
29	  }
30	  return out;
31	}
32	
33	// The union of signal names the due tasks declare — the scheduler collects only
34	// these, so a non-daily slot never pays for daily tasks' signals (DESIGN §3.3).
35	export function signalsUnion(dueTaskSlots) {
36	  const names = new Set();
37	  for (const { task } of dueTaskSlots) for (const name of task.decl.precondition_signals) names.add(name);
38	  return [...names];
39	}
40	
41	// The signal-collection lookback: the widest due task's period plus 1h slack
42	// (DESIGN §3.3). Stateless fixed lookback — overlap is absorbed by dedupe.
43	const FREQUENCY_MS = {
44	  hourly: 3600e3, 'daily-2h': 86400e3, 'daily-1h': 86400e3, daily: 86400e3,
45	  'daily+1h': 86400e3, weekly: 7 * 86400e3, monthly: 31 * 86400e3,
46	};
47	export function windowStart(dueTaskSlots, now) {
48	  const widest = Math.max(0, ...dueTaskSlots.map(({ task }) => FREQUENCY_MS[task.decl.frequency] ?? 86400e3));
49	  return new Date(new Date(now).getTime() - widest - 3600e3).toISOString();
50	}
51	
52	// Run one task's precondition in isolation (DESIGN §3.4). A throwing
53	// precondition converges to a skip with the error recorded — it never sinks the
54	// rest of the run; the CLI escalates a thrown precondition to a workflow-failure
55	// issue separately.
56	export function runPrecondition(task, signals, packConfig) {
57	  try {
58	    const v = task.decl.precondition(signals, packConfig) ?? {};
59	    return {
60	      run: v.run === true,
61	      reason: v.reason ?? '',
62	      context: Array.isArray(v.context) ? v.context : [],
63	    };
64	  } catch (e) {
65	    return { run: false, reason: `precondition threw: ${e.message}`, context: [], error: e.message };
66	  }
67	}
68	
69	// A human-readable job-summary line per evaluated task — the observability the
70	// old plan.json gave (DESIGN §3.6).
71	export function renderSummary(evaluations) {
72	  return evaluations.map((e) => {
73	    const verb = !e.run ? 'skip' : e.inline ? 'run-inline' : e.dispatch?.action ?? 'run';
74	    return `- ${e.pack}/${e.task} [${e.slotId}] ${verb} — ${e.reason || e.dispatch?.reason || ''}`.trimEnd();
75	  }).join('\n');
76	}
77	
78	// Orchestrate one scheduler run into a set of decisions — the reusable core the
79	// CLI wraps with real GitHub I/O. Injected seams:
80	//   collectSignals(names) -> signals object (the declared union, collected once)
81	//   packConfigFor(packId) -> that pack's entry config from .claudinite-checks.json
82	//   existingIssuesFor(pack, task) -> the task family's issues [{number,title,state}]
83	// Returns `{ evaluations }`: one record per due task with its precondition
84	// verdict and, when it runs, either an inline marker (agent_model: none) or a
85	// dispatch decision (planDispatch).
86	export async function planRun({
87	  tasks, schedule, now, lastSuccess,
88	  collectSignals, packConfigFor = () => ({}), existingIssuesFor = async () => [],
89	}) {
90	  const dueList = computeDueTaskSlots(tasks, schedule, now, lastSuccess);
91	  const signals = await collectSignals(signalsUnion(dueList));
92	
93	  const evaluations = [];
94	  for (const { task, slotId } of dueList) {
95	    const pre = runPrecondition(task, signals, packConfigFor(task.pack));
96	    const rec = {
97	      pack: task.pack, task: task.id, slotId,
98	      model: task.decl.agent_model, outcome: task.decl.expected_outcome,
99	      run: pre.run, reason: pre.reason, context: pre.context,
100	    };
101	    if (pre.error) rec.error = pre.error;
102	    if (pre.run) {
103	      // A declared agent_preprocessing runs as a subprocess BEFORE any agent
104	      // (DESIGN §3) — flagged here (pure) for the summary; the CLI shell executes
105	      // it. An agentless task is preprocessing-only; an agentful one hands off to
106	      // the agent after preprocessing succeeds.
107	      if (task.decl.agent_preprocessing) rec.preprocessing = true;
108	      if (isAgentless(task.decl.agent_model)) {
109	        // agent_model: none — no agent and no dispatch issue on success. A task with
110	        // no preprocessing runs the legacy inline worker; with preprocessing it is
111	        // the subprocess above.
112	        rec.inline = true;
113	      } else {
114	        const existing = await existingIssuesFor(task.pack, task.id);
115	        rec.dispatch = planDispatch({ existing, pack: task.pack, task: task.id, slotId });
116	      }
117	    }
118	    evaluations.push(rec);
119	  }
120	  return { evaluations };
121	}
122	
123	// --- CLI: the thin I/O shell the vendored workflow invokes -------------------
124	// Wires the run-ledger read, signal collectors, and issue I/O around planRun,
125	// then acts on each decision (file a labeled dispatch issue, or run an inline
126	// worker) and prints the job summary. All GitHub access here is the Action's
127	// GITHUB_TOKEN — the one sanctioned non-MCP surface (DESIGN §10).
128	
129	// The task family's issues (state=all) via the search API, filtered to exact
130	// prefix — the input planDispatch's exactly-once / at-most-one-open guards read.
131	async function existingIssuesViaSearch(gh, repo, pack, task) {
132	  const q = encodeURIComponent(`repo:${repo} in:title "${DISPATCH_PREFIX} ${pack}/${task}"`);
133	  const { status, json } = await gh(`/search/issues?q=${q}&per_page=100`);
134	  if (status !== 200 || !Array.isArray(json?.items)) return [];
135	  const prefix = `${DISPATCH_PREFIX} ${pack}/${task} `;
136	  return json.items
137	    .filter((i) => `${(i.title ?? '').trim()} `.startsWith(prefix))
138	    .map((i) => ({ number: i.number, title: i.title, state: i.state }));
139	}
140	
141	// Ensure the dispatch labels exist before any is applied — GitHub 422s when you
142	// apply an unknown label (it never creates one on demand), so the scheduler, as the
143	// thing that assigns them, guarantees them here. Idempotent (201 created / 422 already
144	// exists are both success) and self-healing (a deleted label reappears next run), which
145	// is why no separate one-off label-creation step is needed. Exported for the run tests.
146	export async function ensureLabels(gh, repo, labels) {
147	  for (const { name, color, description } of labels) {
148	    const res = await gh(`/repos/${repo}/labels`, { method: 'POST', body: { name, color, description } });
149	    if (res.status !== 201 && res.status !== 422) {
150	      console.log(`! could not ensure label "${name}": ${res.status}`);
151	    }
152	  }
153	}
154	
155	async function main() {
156	  const { makeGh, lastSuccessTime, actionRepoContext } = await import('./signals/gh.mjs');
157	  const { collectSignals } = await import('./signals/index.mjs');
158	  const { discoverTasks } = await import('./discover.mjs');
159	  const { loadConfig } = await import('../checks/helpers/repo-context.mjs');
160	
161	  const root = process.cwd();
162	  const { repo, defaultBranch } = actionRepoContext();
163	  if (!repo) { console.error('GITHUB_REPOSITORY not set — not in an Actions context'); process.exit(1); }
164	  const gh = makeGh();
165	  const config = loadConfig(root);
166	
167	  const { tasks, errors } = await discoverTasks(root, config);
168	  for (const e of errors) console.log(`! ${e.what}`);
169	
170	  const now = new Date();
171	  const lastSuccess = await lastSuccessTime(gh, repo);
172	  const schedule = config.taskScheduler;
173	
174	  const due = computeDueTaskSlots(tasks, schedule, now, lastSuccess);
175	  const sinceIso = windowStart(due, now);
176	  const ctx = {
177	    repo, defaultBranch, now: now.toISOString(), sinceIso, config,
178	    activePacks: config.packs,
179	  };
180	  const packConfigFor = (packId) => config.packConfig?.[packId] ?? {};
181	
182	  const { evaluations } = await planRun({
183	    tasks, schedule, now, lastSuccess,
184	    collectSignals: (names) => collectSignals(gh, ctx, names),
185	    packConfigFor,
186	    existingIssuesFor: (pack, task) => existingIssuesViaSearch(gh, repo, pack, task),
187	  });
188	
189	  // Guarantee the dispatch labels exist before we file any labeled issue — when a
190	  // task will dispatch OR will run preprocessing (which may converge to
191	  // needs-human). An idle run pays nothing.
192	  if (evaluations.some((r) => r.run && (r.preprocessing || (!r.inline && r.dispatch?.action === 'create')))) {
193	    await ensureLabels(gh, repo, SCHEDULER_LABELS);
194	  }
195	
196	  // File the labeled hand-off issue the executor runs (READY_LABEL): first line is
197	  // the task path, body carries the precondition's binding Context (dispatch.mjs).
198	  const fileHandoff = async (rec, taskObj) => {
199	    const title = dispatchTitle({ pack: rec.pack, task: rec.task, slotId: rec.slotId });
200	    const body = dispatchBody({ taskPath: taskObj.taskPath, pack: rec.pack, task: rec.task, slotId: rec.slotId, context: rec.context });
201	    const res = await gh(`/repos/${repo}/issues`, { method: 'POST', body: { title, body, labels: [READY_LABEL] } });
202	    if (res.status >= 300) console.log(`! failed to file dispatch issue for ${rec.pack}/${rec.task}: ${res.status}`);
203	  };
204	
205	  // Converge a failed preprocessing run to a single open needs-human issue for the
206	  // family — at-most-one-open, so a repeatedly-failing task never spams issues.
207	  const fileNeedsHuman = async (rec, why, extra) => {
208	    const existing = await existingIssuesViaSearch(gh, repo, rec.pack, rec.task);
209	    if (existing.some((i) => i.state === 'open')) {
210	      console.log(`  (an open dispatch issue already covers ${rec.pack}/${rec.task} — not filing another)`);
211	      return;
212	    }
213	    const title = dispatchTitle({ pack: rec.pack, task: rec.task, slotId: rec.slotId });
214	    const body = [
215	      `Preprocessing for \`${rec.pack}/${rec.task}\` (slot \`${rec.slotId}\`) failed and needs human triage.`,
216	      '', `- ${why}`, ...extra.map((e) => `- ${e}`),
