1	// store-release worker (agent-preprocessing DESIGN §3/§4). This task is
2	// `agent_model: 'none'` with `agent_preprocessing: 'node worker.mjs'`, so the
3	// scheduler runs THIS FILE as a subprocess (cwd = this task dir) bounded by
4	// `agent_preprocessing_timeout` — there is no agent and no dispatch issue on
5	// success. Its one job is to TRIGGER the repo's vendored `Release to Chrome
6	// Store` orchestrator in daily mode and hand off: the orchestrator's `daily` leg
7	// does the authoritative shipped-file diff, patch bump, and gated submission, so
8	// this worker never decides what ships and never publishes anything itself.
9	//
10	// This absorbs the release workflow's retired 00:30 cron (per-project-scheduling
11	// decision §11.6): the scheduler is the repo's only cron, and this is the surface
12	// that fires the daily release.
13	//
14	// Self-contained — imports only node builtins (the pack-independence barrier
15	// forbids reaching into the engine). It reads its context from the CLAUDINITE_* /
16	// GITHUB_* env the scheduler injects and calls the Actions REST API directly over
17	// the injected GITHUB_TOKEN, the one sanctioned non-MCP surface (DESIGN §10). A
18	// non-204 dispatch, or a throw, exits non-zero — the scheduler then converges the
19	// task to needs-human.
20	
21	import { pathToFileURL } from 'node:url';
22	
23	// The vendored orchestrator's file name and the dispatch mode that runs its daily
24	// leg (release-workflows.mjs STUB_FILE / RELEASE.md §Workflow). Bare literals —
25	// this worker imports nothing from the engine, and the name is the
26	// conformance-pinned fingerprint.
27	const ORCHESTRATOR_FILE = 'chrome-extension-release.yml';
28	const DISPATCH_MODE = 'daily';
29	const API = 'https://api.github.com';
30	
31	// A minimal Actions-REST call over the injected GITHUB_TOKEN. Returns { status }.
32	async function gh(path, { method = 'GET', body } = {}) {
33	  const res = await fetch(`${API}${path}`, {
34	    method,
35	    headers: {
36	      authorization: `Bearer ${process.env.GITHUB_TOKEN}`,
37	      accept: 'application/vnd.github+json',
