1	#!/usr/bin/env node
2	// Perform every declared migration's write side in a checkout:
3	//   - file aliases  — "prefer Y, fall back to X, and rename X -> Y"
4	//   - materialize   — vendor pack templates into the repo's own tree
5	//   - rewrite       — repoint refs in place (idempotent literal replacements)
6	// Idempotent: a no-op once everything has been applied. Dependency-free.
7	//
8	// Two roots. The DEST is the repo being healed (CLAUDE_PROJECT_DIR / cwd). The
9	// TEMPLATE source is the canon that ships the migrations — the parent of this
10	// migrations/ dir: in the canon repo that's the repo root; in a consumer that
11	// mounts Claudinite at .claudinite/, it's .claudinite/ (so a template path like
12	// packs/…/stubs/foo.yml resolves against the mounted pack, while its dest lands
13	// in the consumer's own .github/). The two coincide in the canon repo.
14	//
15	// Runs against a local checkout (a session, CI, or a future SessionStart
16	// self-heal hook wired via bootstrap). In the fleet the identical writes are
17	// performed over the GitHub API by migrations/fleet-apply.mjs (phase 1 of the
18	// daily routine); migrations/fleet-retire.mjs then confirms fleet-wide completion
19	// (0 repos on the legacy shape, quiet for a cycle) and retires the record (phase 3).
20	import { existsSync, renameSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
21	import { dirname, join } from 'node:path';
22	import { fileURLToPath, pathToFileURL } from 'node:url';
23	import { loadMigrations, applyFileAliases, applyMaterializations, applyRewrites } from './registry.mjs';
24	
25	async function main() {
26	  const repoRoot = process.env.CLAUDE_PROJECT_DIR || process.cwd();
27	  const canonRoot = dirname(dirname(fileURLToPath(import.meta.url))); // parent of migrations/
28	  const migrations = await loadMigrations();
29	
