1	// Migration application — the fleet-wide APPLY pass (phase 1 of the daily
2	// maintenance routine, run BEFORE the pack tasks). Migrations-owned: basics
3	// baselining no longer carries the "apply migrations" step. See migrations/README.md
4	// and routines/auto-all-repos-maintenance.md.
5	//
6	// What it does: for every member the routine hands it, compute the member's pending
7	// migration writes — the same three write ops the local applier runs (file aliases,
8	// materialize, rewrite; registry.mjs) — against the member's target branch and land
9	// them. Templates are read from the canon checkout this runs in (the parent of
10	// migrations/); member reads/writes go through the injected `io` (below). Idempotent:
11	// a member already on the canonical shape stages nothing and gets no commit.
12	//
13	// Delivery honors the member's `.claudinite-checks.json` `maintenance.delivery`
14	// (default `auto`; `push`/`pr` are permanent aliases for `auto`/`review`). BOTH modes
15	// land on the stable `claudinite/maintenance` branch and its one open PR — never a
16	// direct commit to the default branch: `review` leaves that PR for the owner; `auto`
17	// arms GitHub auto-merge on it, so it lands automatically once the repo's checks pass
18	// (no run ever blocks on CI). Anything else commits nothing and opens an issue naming it.
19	//
20	// Both lanes regenerate, never reconcile (#332): the desired end-state is
21	// always computed against the DEFAULT branch (the truth being migrated), never
22	// the maintenance branch's own stale copy; writes the branch already carries are
23	// dropped so quiet nights add no commits; and each run first refreshes the
24	// branch from base (io.updateBranchFromBase, optional — a conflict is noted for
25	// the owner, never resolved here) so a weeks-open PR doesn't merge stale-based
26	// content.
27	//
28	// GitHub I/O is a small injected `io` object whose methods map 1:1 to the GitHub MCP
29	// tools the orchestrator drives — there is NO REST client here and no token:
30	//   io.getDefaultBranch(repo)                 -> string | null   (get repo)
31	//   io.read(repo, path[, ref])                -> string | null   (get_file_contents)
32	//   io.ensureBranch(repo, branch, fromBranch)                    (create_branch; idempotent)
33	//   io.commit(repo, branch, files, message)                      (push_files — files:[{path,content}])
34	//   io.remove(repo, branch, path, message)    -> boolean         (delete_file; tolerates absent)
35	//   io.hasOpenPr(repo, headBranch)            -> boolean         (list_pull_requests)
36	//   io.openPr(repo, head, base, title, body)  -> prNumber        (create_pull_request)
37	//   io.enableAutoMerge(repo, prNumber)                           (enable_pr_auto_merge —
38	//                                                arms native auto-merge; the `auto` lane's
39	//                                                land-once-checks-pass, never blocking)
40	//   io.openIssue(repo, title, body)                              (issue_write create)
41	//   io.updateBranchFromBase(repo, headBranch)  [optional]        (update_pull_request_branch
42	//                                                on its open PR; throws on conflict)
43	// The writes land as one `commit` (push_files); a rare file-move's delete follows via
44	// `remove` (a separate commit — MCP has no atomic multi-file+delete, and no active
45	// migration produces a delete). `applyToRepos` returns the migration ids it applied
46	// this cycle; the orchestrator hands that set to the retire pass as its quiescence
47	// evidence (a migration touched this cycle is never retired this cycle).
48	
49	import { existsSync, readFileSync } from 'node:fs';
50	import { dirname, join } from 'node:path';
51	import { fileURLToPath } from 'node:url';
52	import { applyFileAliases, applyMaterializations, applyRewrites } from './registry.mjs';
53	
54	const MAINT_BRANCH = 'claudinite/maintenance';
55	const canonRoot = dirname(dirname(fileURLToPath(import.meta.url))); // the checkout ships the templates
56	const readTemplate = (p) => (existsSync(join(canonRoot, p)) ? readFileSync(join(canonRoot, p), 'utf8') : null);
57	
58	// Stage a member's whole pending migration write-set in memory (reading `branch`),
59	// so it commits as ONE commit. Staged-aware readers let a later op see an earlier
60	// op's write. Returns { files, deletes, ids } or null when nothing changed.
61	async function stageMemberWrites(io, fullName, branch, migrations) {
62	  const files = new Map(); const deletes = new Set(); const ids = new Set();
63	  const read = async (p) => {
64	    if (files.has(p)) return files.get(p);
65	    if (deletes.has(p)) return null;
66	    return io.read(fullName, p, branch);
67	  };
68	  const exists = async (p) => (await read(p)) !== null;
69	  const write = (p, c) => { files.set(p, c); deletes.delete(p); };
70	  const move = async (from, to) => {
71	    const content = await read(from);
72	    if (content == null) return;
73	    files.set(to, content); files.delete(from); deletes.add(from);
74	  };
75	  for (const m of migrations) {
76	    const a = await applyFileAliases(m, { exists, move });
77	    const mat = await applyMaterializations(m, { readTemplate, read, write });
78	    const rw = await applyRewrites(m, { read, write });
79	    if (a.length || mat.length || rw.length) ids.add(m.id);
80	  }
81	  return (files.size || deletes.size) ? { files, deletes, ids } : null;
82	}
83	
84	// Apply pending migrations to one repo the routine handed us; returns the migration
85	// ids applied (empty when nothing was pending). Honors the repo's delivery preference.
86	export async function applyToRepo(io, fullName, migrations) {
87	  const defaultBranch = await io.getDefaultBranch(fullName);
88	  if (!defaultBranch) return { ids: [], note: `${fullName}: unreadable` };
89	  const cfg = await io.read(fullName, '.claudinite-checks.json');
90	  let rawDelivery = 'auto-merge';
91	  try { rawDelivery = JSON.parse(cfg ?? '{}')?.maintenance?.delivery ?? 'auto-merge'; } catch { rawDelivery = 'auto-merge'; }
92	  // `push`/`pr` are the pre-rename aliases for `auto`/`review` — accepted permanently
93	  // (the maintenance-delivery-rename migration rewrites the stored value, but the
94	  // tolerance outlives the record, so retiring it strands nothing).
95	  const delivery = rawDelivery === 'push' || rawDelivery === 'auto' ? 'auto-merge' : rawDelivery === 'pr' ? 'review' : rawDelivery;
96	
97	  if (delivery !== 'auto-merge' && delivery !== 'review') {
98	    await io.openIssue(
99	      fullName,
100	      'Claudinite maintenance: unrecognized delivery preference',
101	      `\`.claudinite-checks.json\` sets \`maintenance.delivery: "${rawDelivery}"\`, which is neither \`auto-merge\` nor \`review\`. `
102	        + 'Migrations were not applied this run. Set it to `auto` or `review`.',
103	    );
104	    return { ids: [], note: `${fullName}: unrecognized delivery "${rawDelivery}" — opened an issue, applied nothing` };
105	  }
