107	  // Both deliveries land on the stable `claudinite/maintenance` branch and its one
108	  // PR — never a direct commit to the default branch. `review` leaves that PR for the
109	  // owner; `auto` arms GitHub auto-merge on it, so it lands automatically
110	  // once the repo's checks pass (the run never blocks on CI). How strictly "once
111	  // checks pass" holds depends on the repo requiring its checks (branch protection);
112	  // with none required, GitHub lands the PR as soon as it's mergeable.
113	  const notes = [];
114	
115	  // Desired end-state is ALWAYS computed against the default branch — the truth
116	  // being migrated — never the maintenance branch's own copy (#332).
117	  const staged = await stageMemberWrites(io, fullName, defaultBranch, migrations);
118	  if (!staged) return { ids: [], note: undefined };
119	
