129	  // Drop writes the branch already carries, so an unmerged PR doesn't collect an
130	  // identical commit every night.
131	  let files = [...staged.files].map(([path, content]) => ({ path, content }));
132	  let deletes = [...staged.deletes];
133	  const pending = [];
134	  for (const f of files) {
135	    if ((await io.read(fullName, f.path, MAINT_BRANCH)) !== f.content) pending.push(f);
136	  }
137	  files = pending;
138	  const pendingDeletes = [];
139	  for (const path of deletes) {
140	    if ((await io.read(fullName, path, MAINT_BRANCH)) !== null) pendingDeletes.push(path);
141	  }
142	  deletes = pendingDeletes;
143	  if (!files.length && !deletes.length) {
144	    return { ids: [], note: notes.length ? `${fullName}: ${notes.join('; ')}` : undefined };
145	  }
146	
147	  if (files.length) await io.commit(fullName, MAINT_BRANCH, files, 'Apply Claudinite migrations');
148	  for (const path of deletes) {
