1	// The task declaration contract (per-project-scheduling DESIGN §1) — the single
2	// source of truth for what a `tasks/<name>/task.mjs` default export must carry.
3	// Both the author-time `task-declaration-shape` check and the executor-side
4	// `validate-dispatch` validate against this one function, so the accepted shape
5	// can never drift between the two surfaces.
6	
7	import { FREQUENCIES } from './slots.mjs';
8	import { MODEL_FAMILIES } from './model-map.mjs';
9	
10	// A declared timeout is always a whole number of seconds, > 0.
11	const isPositiveInt = (n) => Number.isInteger(n) && n > 0;
12	
13	// A preprocessing command must stay inside its own task directory — no absolute
14	// path and no `..` traversal in the command string — the same containment the
15	// worker-file rule gives agent_instructions (agent-preprocessing DESIGN §2).
16	const escapesTaskDir = (cmd) => /(^|\s)\//.test(cmd) || cmd.includes('..');
17	
18	// The write ceiling a task declares (DESIGN §1, §4). A declared MAXIMUM, not a
19	// promise: `none` may never open a PR, `open-pr` may open but never merge,
20	// `merged-pr` may arm auto-merge. "No change" is always legal.
21	export const OUTCOMES = ['none', 'open-pr', 'merged-pr'];
22	
23	// The signal-collector vocabulary (DESIGN §3.3). A task collects only the union
24	// of what its due tasks declare. `fleet` is canon-only (consumers cannot declare
25	// it) — that restriction is enforced where signals are collected, not here; the
26	// shape check only asserts a declared name is a real collector.
27	export const SIGNAL_NAMES = [
28	  'commits', 'prs', 'issues', 'branches', 'release',
29	  'localPacks', 'sharedMount', 'conversationLogs', 'stamp', 'fleet',
30	];
31	
32	// Validate one task declaration. Returns an array of `{ what, fix }` problems —
33	// empty means the declaration is well-formed. Pure: no I/O, no imports of the
34	// task itself; the caller supplies the already-loaded default export.
