// Task discovery for the scheduler (per-project-scheduling DESIGN §3.2). One
// uniform scan of every ACTIVE pack's `tasks/<name>/task.mjs`, activation-gated
// by the repo's `packs` declaration exactly like checks and skills. Reuses the
// pack registry so the same scan works across all three layouts without knowing
// any of them: canon packs at `packs/`, a consumer's vendored canon at
// `.claudinite/shared/packs/`, and local packs at `.claudinite/local/packs/`
// (each pack carries its own resolved `dir`).
//
// Frequency filtering is deliberately NOT done here — discover returns every
// active, well-formed task; the run entrypoint intersects them with the due
// slots (slots.mjs). Keeping the two apart keeps each pure and separately
// testable. A task whose task.mjs fails to import or violates the declaration
// contract is dropped into `errors` (fail-soft, per-task), never sinking the
// scan.

import { readdirSync, existsSync } from 'node:fs';
import { join, relative } from 'node:path';
import { pathToFileURL } from 'node:url';
import { loadPacks, isActive } from '../pack_loader/pack-registry.mjs';
import { validateTaskDeclaration } from './task-contract.mjs';

// Discover every task the repo's active packs contribute. Returns
// `{ tasks, errors }` where each task is
// `{ pack, id, taskDir, taskPath, decl }` — `taskPath` is the repo-relative
// path to the worker file's directory's task.md (the dispatch issue's first
// line), `decl` the validated declaration.
export async function discoverTasks(root, config) {
  const errors = [];
  const packs = await loadPacks({ localRoot: root });
  const active = packs.filter((p) => isActive(p, config));

  const tasks = [];
  for (const pack of active) {
    const tasksRoot = join(pack.dir, 'tasks');
    if (!existsSync(tasksRoot)) continue;
    let names;
    try {
      names = readdirSync(tasksRoot, { withFileTypes: true })
        .filter((d) => d.isDirectory()).map((d) => d.name).sort();
    } catch (e) {
      errors.push({ pack: pack.id, what: `${pack.id}'s tasks/ is not a readable directory: ${e.message}`, fix: `make ${relative(root, tasksRoot)} a directory (or remove it)` });
      continue;
    }
    for (const name of names) {
      const taskDir = join(tasksRoot, name);
      const mjs = join(taskDir, 'task.mjs');
      if (!existsSync(mjs)) continue;
      let decl;
      try {
        decl = (await import(pathToFileURL(mjs).href)).default;
      } catch (e) {
        errors.push({ pack: pack.id, task: name, what: `${relative(root, mjs)} failed to import: ${e.message}`, fix: 'fix or remove the task' });
        continue;
      }
      const problems = validateTaskDeclaration(decl);
      if (problems.length) {
        errors.push({ pack: pack.id, task: name, what: `${relative(root, mjs)} is not a valid task declaration: ${problems.map((p) => p.what).join('; ')}`, fix: problems[0].fix });
        continue;
      }
      // A local pack's dir-name is its id (enforced by the registry); the task's
      // directory name should likewise match its declared id — a mismatch would
      // make the dispatch path and the declaration disagree.
      if (decl.id !== name) {
        errors.push({ pack: pack.id, task: name, what: `task in ${relative(root, taskDir)} declares id "${decl.id}" but its directory is "${name}"`, fix: 'rename the directory to the task id, or set the id to the directory name' });
        continue;
      }
      tasks.push({
        pack: pack.id,
        id: decl.id,
        taskDir,
        taskPath: `${relative(root, taskDir).split('\\').join('/')}/task.md`,
        decl,
      });
    }
  }
  return { tasks, errors };
}

// The one vendored place that maps a task's declared model FAMILY to the model
// the executor dispatches its subagent at (per-project-scheduling DESIGN §1, §3).
// A model-generation bump is a single edit HERE — task files and the executor
// only ever speak in families, never concrete ids.
//
// The resolved value is what the executor passes as the subagent's model. Short
// family names are themselves valid model selectors, so they are the safe
// default; to pin a task tier to a concrete dated snapshot, change only that
// family's value in MODEL_MAP below (nothing else needs to move).

export const MODEL_FAMILIES = ['opus', 'sonnet', 'haiku', 'none'];

// family → the model the executor dispatches at. `none` is agentless (the worker
// is code the scheduler runs inline — no subagent, no model), so it maps to null.
export const MODEL_MAP = {
  opus: 'opus',
  sonnet: 'sonnet',
  haiku: 'haiku',
  none: null,
};

// `none` means "pure code, no agent" (DESIGN §1) — the scheduler runs the
// worker .mjs inline rather than filing a dispatch issue.
export const isAgentless = (family) => family === 'none';

// Resolve a family to its concrete model, or throw on an unknown family (the
// task-declaration-shape check is the author-time guard; this is the runtime
// backstop for the executor/validator).
export function resolveModel(family) {
  if (!Object.prototype.hasOwnProperty.call(MODEL_MAP, family)) {
    throw new Error(`unknown model family "${family}" — valid families: ${MODEL_FAMILIES.join(', ')}`);
  }
  return MODEL_MAP[family];
}

// gcec local task: fallback-extractor-improvements — the daily attempt to make the GENERIC
// fallback extractor recover more of what the dedicated per-site sources get
// (per-project-scheduling DESIGN §6). Worker: task.md. Most runs correctly change
// nothing — the coverage gate already banks every prior win — so a forced or fake
// win is worse than none; no win → no branch, no PR.
//
// Self-contained (imports nothing): the whole contract is this default export.

export default {
  id: 'fallback-extractor-improvements',
  frequency: 'daily',            // fires on the repo's daily anchor hour
  precondition_signals: ['commits'],
  agent_model: 'opus',                 // closing a real generic-extractor gap is heavy judgment
  expected_outcome: 'open-pr',            // a generic win lands as a PR the owner reviews; never auto-merged

  agent_instructions: 'task.md',

  // This is the old preconditions.sh, moved into code over the `commits` signal
  // (DESIGN §6): the result is a pure function of the source, and most days nothing
  // meaningful lands, so a run over unchanged code would re-derive yesterday's
  // answer while burning a full model run. `commits.substantiveChange` is exactly
  // the shell's "a commit touched real source, not only docs/GENERATED" notion —
  // fixing the live cadence bug the weekly cron caused (daily spec vs weekly fire).
  // When in doubt the day still runs: a run that finds nothing is cheap and makes
  // no PR; a too-clever skip that misses a real opportunity is not.
  precondition(signals) {
    const commits = signals.commits ?? {};
    if (!commits.substantiveChange) {
      return { run: false, reason: 'no meaningful code change in the window (idle, or docs/generated churn only)' };
    }
    const shas = (commits.list ?? []).filter((c) => c.substantive).map((c) => c.sha.slice(0, 7));
    return {
      run: true,
      reason: `${shas.length} meaningful commit(s) in the window`,
      context: [
        `Scope: the ${shas.length} substantive commit(s) in the window — ${shas.join(', ')}.`,
        'Most runs correctly change nothing — only open a PR on a real generic-extractor win that clears the coverage gate; a forced or fake win is worse than none.',
      ],
    };
  },
};

