1	// The dispatch issue — how a due (task, slot) becomes exactly-once, bounded,
2	// recoverable agent work (per-project-scheduling DESIGN §4). This module is the
3	// PURE half: issue identity (title/body/parse) and the create / skip / suppress
4	// decision over the issues that already exist. A thin scheduler shell does the
5	// GitHub I/O (search state=all, create, label, comment) and applies the verdict
6	// — the "should I file this" decision is always code here, never the shell's
7	// judgment (the same split the fleet planner uses).
8	//
9	// All behavior-defining content (agent_model, expected_outcome, agent_instructions) is read from the
10	// tracked task files, never from the issue — the body only points at the task
11	// file and carries the precondition's binding Context (DESIGN §4).
12	
13	// The labels this machinery drives. `ready-for-agent` is what the executor
14	// routine fires on; `needs-human` is the single triage state every anomaly
15	// converges to (DESIGN §4 lifecycle). Kept here as the shared source for the
16	// scheduler side; the executor reuses these plus `agent-running`.
17	export const READY_LABEL = 'ready-for-agent';
18	export const AGENT_RUNNING_LABEL = 'agent-running';
19	export const NEEDS_HUMAN_LABEL = 'needs-human';
20	export const WORKFLOW_FAILURE_LABEL = 'workflow-failure';
21	
22	// The full label set the scheduler + executor drive, each with the colour and
23	// description a bootstrap one-off would have given it. The scheduler ENSURES every
24	// one exists (create-if-missing, idempotent) right before it dispatches — so there
25	// is no separate label-creation step to run or forget, and a deleted label
26	// self-heals on the next run. This is load-bearing, not cosmetic: GitHub does not
27	// create a label when you apply it (the issues API 422s on an unknown label), so
28	// the thing that assigns a label must guarantee it first — the
29	// gha/label-create-before-add principle, enforced in code here.
30	export const SCHEDULER_LABELS = [
31	  { name: READY_LABEL, color: '0e8a16', description: 'Claudinite scheduler: dispatch issue ready for the executor to run' },
32	  { name: AGENT_RUNNING_LABEL, color: 'fbca04', description: 'Claudinite scheduler: the executor has claimed this issue and is running it' },
33	  { name: NEEDS_HUMAN_LABEL, color: 'd93f0b', description: 'Claudinite scheduler: an anomaly that converged here for human triage' },
34	  { name: WORKFLOW_FAILURE_LABEL, color: 'b60205', description: 'Claudinite scheduler: a scheduler run or task failed' },
35	];
36	
37	// Title: `[claudinite-task] <pack>/<task> <slot-id>` (DESIGN §4). The prefix is
38	// what keeps these issues invisible to the scheduler's own signals (self-trigger
39	// exclusion) and searchable as a family.
40	export const DISPATCH_PREFIX = '[claudinite-task]';
41	
42	export const dispatchTitle = ({ pack, task, slotId }) => `${DISPATCH_PREFIX} ${pack}/${task} ${slotId}`;
43	
44	// The (pack, task) family key — every slot's title for one task starts with
45	// `<key> ` (the trailing space before the slot id is load-bearing: it stops
46	// `foo/extract` from matching `foo/extract-more`).
47	export const dispatchTaskKey = ({ pack, task }) => `${DISPATCH_PREFIX} ${pack}/${task}`;
48	
49	// pack and task ids are single path segments (no slash, no space); the slot id
50	// is the trailing non-space token.
51	const DISPATCH_TITLE_RE = /^\[claudinite-task\]\s+([^/\s]+)\/([^/\s]+)\s+(\S+)$/;
52	
53	export function parseDispatchTitle(title) {
54	  const m = DISPATCH_TITLE_RE.exec(String(title ?? '').trim());
55	  return m ? { pack: m[1], task: m[2], slotId: m[3] } : null;
56	}
57	
58	// Is this a scheduler dispatch issue? The self-trigger exclusion the signal
59	// collectors apply so the scheduler never sees its own dispatch issues as work.
60	export const isDispatchTitle = (title) => parseDispatchTitle(title) !== null;
61	
62	// The dispatch issue body (DESIGN §4). First line is the task-file path — the
63	// only thing the executor reads to locate the worker; everything below is human
64	// framing plus the precondition's binding Context. The Context block is emitted
65	// only when the precondition produced lines (an empty scope has nothing to bind).
66	export function dispatchBody({ taskPath, pack, task, slotId, context = [] }) {
67	  const lines = [taskPath, ''];
68	  if (context.length) {
69	    lines.push(
70	      `Execute the Claudinite task above (pack \`${pack}\`, task \`${task}\`, slot \`${slotId}\`).`,
71	      'The Context section below is binding scope — do not re-decide it.',
72	      '',
73	      '### Context',
74	    );
75	    for (const c of context) lines.push(`- ${c}`);
76	  } else {
77	    lines.push(`Execute the Claudinite task above (pack \`${pack}\`, task \`${task}\`, slot \`${slotId}\`).`);
78	  }
79	  return lines.join('\n') + '\n';
80	}
81	
82	// The filing decision for one due (task, slot), given `existing` — the issues
83	// the shell fetched for this task's family (title starts with the task key),
84	// each `{ number, title, state }` with state 'open' | 'closed'. Two guards
85	// (DESIGN §4):
86	//   - exactly-once per (task, slot): a state=all title match for THIS slot → skip
87	//     (makes double-runs and crash-retries safe).
88	//   - at-most-one-open per task: any OPEN family issue (any slot) suppresses a
89	//     new filing → an executor outage accumulates at most one issue per task.
90	// Otherwise: create (the shell files it labeled `ready-for-agent`).
91	export function planDispatch({ existing = [], pack, task, slotId }) {
92	  const title = dispatchTitle({ pack, task, slotId });
93	  const keyPrefix = `${dispatchTaskKey({ pack, task })} `;
94	  const family = existing.filter((i) => `${(i.title ?? '').trim()} `.startsWith(keyPrefix));
95	
96	  if (family.some((i) => (i.title ?? '').trim() === title)) {
97	    return { action: 'skip', reason: `dispatch issue for slot ${slotId} already exists (exactly-once)` };
98	  }
99	  const open = family.find((i) => i.state === 'open');
100	  if (open) {
101	    return { action: 'suppress', openIssue: open.number, reason: `an open dispatch issue (#${open.number}) already covers ${pack}/${task}` };
102	  }
103	  return { action: 'create', title, label: READY_LABEL, reason: `no dispatch issue yet for ${pack}/${task} slot ${slotId}` };
104	}
105	
106	// The period one slot id represents, from its leading kind char (h/d/w/m). Used
107	// only for the stale-issue backstop's threshold; daily-family slots all span a
108	// day. Monthly uses 31 days so the ~2-period threshold never fires early in a
109	// long month.
110	const SLOT_PERIOD_MS = { h: 3600e3, d: 86400e3, w: 7 * 86400e3, m: 31 * 86400e3 };
111	
112	function slotPeriodMs(slotId) {
113	  return SLOT_PERIOD_MS[String(slotId ?? '')[0]] ?? null;
114	}
115	
116	// Open dispatch issues older than `factor` of their own period (DESIGN §4: ~2
117	// periods) — the scheduler's backstop when no executor session drains them. The
118	// shell adds the escalation comment + `needs-human` to each. `issue.created_at`
119	// is the ISO string GitHub returns; a title that doesn't parse (or an unknown
120	// slot kind) is never stale here.
121	export function staleDispatchIssues(openIssues = [], now, { factor = 2 } = {}) {
122	  const nowMs = new Date(now).getTime();
123	  return openIssues.filter((issue) => {
124	    const parsed = parseDispatchTitle(issue.title);
125	    if (!parsed) return false;
126	    const period = slotPeriodMs(parsed.slotId);
