import { test } from 'node:test';
import assert from 'node:assert/strict';
import { runPreprocessing, preprocessingFailure } from '../../engine/scheduler/preprocess.mjs';

const NODE = process.execPath; // the running node, so the tests don't assume PATH

test('runPreprocessing: a clean exit is ok', async () => {
  const r = await runPreprocessing(`"${NODE}" -e "process.exit(0)"`, { taskDir: process.cwd(), env: process.env, timeoutSeconds: 10 });
  assert.equal(r.ok, true);
  assert.equal(r.timedOut, false);
  assert.equal(r.code, 0);
});

test('runPreprocessing: a non-zero exit is a failure carrying the code', async () => {
  const r = await runPreprocessing(`"${NODE}" -e "process.exit(3)"`, { taskDir: process.cwd(), env: process.env, timeoutSeconds: 10 });
  assert.equal(r.ok, false);
  assert.equal(r.timedOut, false);
  assert.equal(r.code, 3);
});

test('runPreprocessing: an overrun is hard-killed and reported timedOut', async () => {
  const r = await runPreprocessing(`"${NODE}" -e "setTimeout(()=>{}, 10000)"`, { taskDir: process.cwd(), env: process.env, timeoutSeconds: 0.3 });
  assert.equal(r.ok, false);
  assert.equal(r.timedOut, true);
  assert.notEqual(r.signal, null); // killed by signal, not a clean exit
});

test('runPreprocessing: the child inherits the injected env', async () => {
  const cmd = `"${NODE}" -e "process.exit(process.env.CLAUDINITE_SLOT_ID === 'd2026' ? 0 : 1)"`;
  const r = await runPreprocessing(cmd, { taskDir: process.cwd(), env: { ...process.env, CLAUDINITE_SLOT_ID: 'd2026' }, timeoutSeconds: 10 });
  assert.equal(r.ok, true);
});

test('runPreprocessing: a command that cannot start is a failure, not a throw', async () => {
  const r = await runPreprocessing('definitely-not-a-real-command-xyz', { taskDir: process.cwd(), env: process.env, timeoutSeconds: 10 });
  assert.equal(r.ok, false);
});

test('preprocessingFailure: distinguishes a timeout from a non-zero exit', () => {
  assert.match(preprocessingFailure({ timedOut: true, code: null, stderr: '' }), /exceeded its agent_preprocessing_timeout/);
  assert.match(preprocessingFailure({ timedOut: false, code: 2, stderr: '' }), /exited 2/);
  assert.match(preprocessingFailure({ timedOut: false, code: null, stderr: 'boom\n' }), /could not run: boom/);
});

import { readdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

// The synchronous migration-registry surface for the CHECK layer. It lives in
// the engine lib — not migrations/ — because pack checks consult it
// (`migrationActive` gates an in-flight transition's legacy tolerance) and a
// pack imports only its own files and the engine surface (pack-independence):
// the canon-internal migrations/ tree is never vendored, so an import into it
// would crash every vendored consumer. Self-locating relative to the engine
// root, so in a vendored consumer — where migrations/ is absent by design —
// every query answers "no active migrations": a flipped member runs the
// canonical shapes, no tolerance needed. The full registry
// (migrations/registry.mjs) builds on this same surface canon-side.
export const MIGRATIONS_SUBDIR = 'active_migrations';
const specsDir = join(dirname(dirname(dirname(dirname(fileURLToPath(import.meta.url))))), 'migrations', MIGRATIONS_SUBDIR); // <canon>/engine/checks/helpers/
export const isSpec = (f) => f.endsWith('.mjs') && !f.endsWith('.test.mjs');
// Tolerant of an absent/empty folder — a vendored consumer, or a canon
// checkout after every record has retired.
export const specFiles = () => { try { return readdirSync(specsDir).filter(isSpec).sort(); } catch { return []; } };

// True while a migration whose file name carries `slug` is still present — a
// check consults it to know whether an in-flight transition's legacy shape is
// still tolerated. When the census auto-retires the migration (deletes the
// file), this flips to false and the tolerance vanishes with it: the resolver
// pattern, expressed synchronously (checks run synchronously and cannot await
// the async spec loader).
export function migrationActive(slug) {
  return specFiles().some((f) => f.includes(slug));
}

// Pack independence (extending.md; the canon-side `pack-independence` barrier):
// packs no longer import each other's code — a fixed folder-barrier is now
// CONTRIBUTED as manifest data (`requires` the mechanism pack +
// `contributes` on pack.mjs; the engine builds the rule) and the shared
// path/migration helpers moved into the vendored engine lib (engine/checks/helpers/).
// The old code-composition export (`defineBarrier`) is gone.
//
// Canon-side the conversion is complete (rule first, then the fixes — one
// commit each). Member-side there are no mechanical ops: nothing in a
// consumer's tree is renamed or rewritten. The AGENTIC note for the nightly
// worker: if a member's own local packs (.claudinite/local_packs/) composed a
// barrier by importing the shared engine, convert each to the contribution
// shape — move the barrier object (id, edges, description, why, doc,
// crossingExcuse, gateDir) onto the local pack's manifest under
// `contributes` and add the mechanism pack to its `requires`. A local pack
// still importing the removed export fails loudly at pack discovery (the
// runner's fail-soft config finding names the broken manifest) — that
// diagnostic is the member-side signal. Consumers with no such local packs
// need nothing.
//
// retire: 'auto' — the durable enforcement is the check, which every member
// runs from its own snapshot; this record only carries the one-time
// conversion guidance through the fleet's next cycles.
export default {
  id: 'pack-independence',
  landed: '2026-07-19',
  summary: 'packs compose by declaration + contributed config, never code imports; local packs that imported the shared barrier engine convert to `contributes` on their manifest',
  // The AGENTIC note above, now machine-readable (agent-preprocessing DESIGN §7):
  // baselining's deterministic preprocessing detects this and escalates to the
  // agent stage instead of advancing the stamp past it. There are no mechanical
  // member-side ops, so this is the record's whole member-side work.
  agentic: {
    model: 'sonnet',
    instructions: 'If a member local pack (.claudinite/local/packs/) composed a barrier by importing the shared engine, convert it to the contribution shape: move the barrier object (id, edges, description, why, doc, crossingExcuse, gateDir) onto the local pack manifest under `contributes`, and add the mechanism pack to its `requires`. A member with no such local pack needs nothing.',
  },
};

