1	#!/usr/bin/env node
2	// World-scope conformance runner (see DESIGN.md): the rules that audit repo
3	// state as it exists now, plus the pack-agnostic settings/load integrity
4	// diagnostics (malformed config, an unknown pack, a broken pack.mjs). Rules that
5	// judge the current change (`scope: 'work'`) run in check_the_work.mjs, which
6	// this file shares no code with — only the scope-blind mechanism helpers
7	// (run-active-pack-rules.mjs, report-findings.mjs). It names NO pack: adoption
8	// interview hygiene is a skill-owned check that rides its own pack's activation,
9	// and a malformed `questions` field is a load fault the pack registry reports.
10	// Wired into the project's test/CI flow, not the Stop hook. Dependency-free Node ≥18.
11	//   (default)   whole-repo sweep — milliseconds on a text corpus, sees cross-file breakage
12	//   --changed   transitional: scope to files changed vs the merge-base with main
13	//               (adopting a repo with a backlog only — not the enforcement default)
14	//   --base REF  override the base ref
15	//   --list      machine-readable catalog of every rule, both scopes (id, severity, description, doc)
16	//   --init      write .claudinite-checks.json — basics plus the fingerprinted packs
17	import { writeFileSync, existsSync } from 'node:fs';
18	import { join } from 'node:path';
19	import { buildContext } from './helpers/repo-context.mjs';
20	import { discoverPacks, resolveDeclaredPacks } from '../pack_loader/pack-registry.mjs';
21	import { runActivePackRules, contributedRules } from './run-active-pack-rules.mjs';
22	import { reportFindings } from './report-findings.mjs';
23	
24	const configError = (what, fix) => ({
25	  rule: 'config', severity: 'blocking', file: '.claudinite-checks.json', line: null,
26	  what, why: 'the settings file is what executes — a bad key, value, or pack name silently changes what runs', fix, doc: 'engine/checks/README.md',
27	});
28	
29	const args = process.argv.slice(2);
30	const has = (flag) => args.includes(flag);
31	const value = (flag) => (args.includes(flag) ? args[args.indexOf(flag) + 1] : null);
32	const root = value('--root') || process.cwd();
33	
34	if (has('--list')) {
35	  const { packs } = await discoverPacks({ localRoot: root });
36	  const rules = [
37	    ...packs.flatMap((p) => p.rules ?? []),
38	    ...packs.flatMap((p) => p.skillChecks ?? []),
39	    ...packs.flatMap((p) => contributedRules(p, packs)),
40	  ];
41	  for (const r of rules.sort((a, b) => a.id.localeCompare(b.id))) {
42	    console.log(`${r.id}\t${r.severity}\t${r.description}\t${r.doc}`);
43	  }
44	  process.exit(0);
45	}
46	
47	if (has('--init')) {
48	  const path = join(root, '.claudinite-checks.json');
49	  if (existsSync(path)) {
50	    console.log(`${path} already exists — leaving it as-is.`);
51	    process.exit(0);
52	  }
53	  const { packs } = await discoverPacks({ localRoot: root });
54	  const ctx = buildContext({ root, mode: 'all' });
55	  // No pack is active by default, so the baseline is seeded as an explicit
56	  // declaration alongside the fingerprinted packs: every pack that flags
57	  // `seededByDefault` is written in (discovered structurally — the engine names
58	  // no pack), plus the ones a fingerprint detects. A seeded pack is still
59	  // opt-out-able where its own policy allows (baselining re-adds only the packs
60	  // whose absence it treats as drift), so removing a seeded declaration can
61	  // stick; each seeded pack ships its own one-time seed migration for the fleet.
62	  // Local packs are declared by hand, never fingerprinted or seeded — exclude
63	  // them from --init's seeding so a repo that already carries local packs (but
64	  // no config yet) doesn't auto-declare them.
65	  const seeded = packs.filter((p) => p.seededByDefault && !p.local).map((p) => p.id);
66	  const detected = [...seeded, ...packs.filter((p) => p.detect && !p.local && p.detect(ctx)).map((p) => p.id)];
67	  // A pack can't be imported without its dependencies — pull each declared pack's
68	  // `requires` closure into the declaration so it's complete and visible.
69	  const declared = resolveDeclaredPacks(detected, packs);
70	  // maintenance.delivery is deliberately materialized, not defaulted — the selection
71	  // must be visible in the file where a project would change it (see engine/checks/README.md).
72	  // Only what carries a decision: the declaration and the always-explicit
73	  // delivery. Empty rules/accept boilerplate is noise, not settings (#385);
74	  // loadConfig defaults absent keys.
75	  writeFileSync(path, `${JSON.stringify({ packs: declared, maintenance: { delivery: 'auto-merge' } }, null, 2)}\n`);
76	  console.log(`Wrote ${path} (packs: ${declared.join(', ')}).`);
77	  // The adoption interview (surfacing each declared pack's pending questions) is
78	  // driven by the adopt-claudinite skill / bootstrap.md, and nudged every session
79	  // by the SessionStart interview-check step — not printed here, so this runner
80	  // imports no pack.
81	  process.exit(0);
82	}
83	
84	const { packs, errors: packErrors } = await discoverPacks({ localRoot: root });
85	const ctx = buildContext({ root, mode: has('--changed') ? 'changed' : 'all', baseOverride: value('--base') });
86	
87	// Settings/load integrity — pack-agnostic, so the world runner owns them.
88	// Settings validity is checked at load: malformed JSON, an unknown
89	// property, and a wrong pack name are all equally settings errors. loadConfig
90	// reports the first two; the runner adds unknown pack names (only it holds the
91	// registry) and broken/duplicate local pack.mjs faults.
92	const findings = [];
93	for (const e of ctx.config.errors) findings.push(configError(e.what, e.fix));
94	for (const e of packErrors) findings.push(configError(e.what, e.fix));
95	// knownIds spans canon AND local packs, so a declared local pack id is valid and
96	// the unknown-pack message lists it among the declarable packs. ctx.config.packs
97	// is loadConfig's normalized view — bare ids, a namespaced local_packs/<name>
98	// declaration already resolved through packEntryId.
99	const knownIds = new Set(packs.map((p) => p.id));
100	for (const name of ctx.config.packs) {
101	  if (typeof name === 'string' && !knownIds.has(name)) {
102	    findings.push(configError(`declares unknown pack "${name}"`, `remove it or fix the name — declarable packs: ${[...knownIds].sort().join(', ')}`));
103	  }
104	}
105	// (Adoption-interview hygiene is a skill-owned check that runs below with the
106	// other active-pack rules; a malformed `questions` field arrives as a load fault
107	// in packErrors above. Neither names a pack here.)
108	
109	// The world rules: everything not scoped to the work. A broken contributedRules
110	// seam is a config-level fault surfaced here (the world runner owns diagnostics).
111	findings.push(...runActivePackRules(ctx, packs, {
112	  includeRule: (rule) => rule.scope !== 'work',
113	  onContributeError: (pack, e) => findings.push(configError(
114	    `the "${pack.id}" pack's contributedRules failed: ${e.message}`, 'fix the pack manifest, or the contribution it interprets')),
115	}));
116	
117	const blocking = reportFindings(findings, ctx.config, { scopeLabel: 'world', mode: ctx.mode, baseRef: ctx.baseRef });
118	process.exit(blocking ? 1 : 0);
119

1	// Fresh-path wiring convergence (agent-preprocessing DESIGN §7, the primitive
2	// absorbed from #405). The deterministic half of baselining's self-refresh that
3	// has nothing to do with the vendored mount's CONTENT: the repo-specific wiring a
4	// scheduled Claudinite consumer must carry, converged idempotently in code so the
5	// nightly refresh never needs a model to re-enact bootstrap's prose.
6	//
7	// One source of truth: bootstrap Part 5 (the settings hooks) + Part 6 (the
8	// scheduler workflow) describe this same set for a fresh adoption; this module is
9	// what both bootstrap and baselining CALL, so the wiring can never drift between
10	// "how a repo is set up" and "how the nightly keeps it set up".
11	//
12	// Operates on a repo working tree at `root` with node:fs directly (like
13	// apply-vendor-set.mjs), returning a summary of what it changed — idempotent: a
14	// repo already converged produces an empty change list.
15	
16	import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
17	import { join, dirname } from 'node:path';
18	import { pathToFileURL } from 'node:url';
19	import { hashedCron } from './hash-minute.mjs';
20	
21	// The settings-hook registrations a scheduled repo carries (bootstrap Part 5).
22	// Ensured present without clobbering — a set-union keyed on the command string, so
23	// a repo's own extra hooks and any hand-added entries survive untouched.
24	export const REQUIRED_HOOKS = [
25	  { event: 'SessionStart', matcher: null, command: 'bash $CLAUDE_PROJECT_DIR/.claudinite/shared/engine/hooks/session-start-command.sh' },
26	  { event: 'Stop', matcher: null, command: 'node $CLAUDE_PROJECT_DIR/.claudinite/shared/engine/hooks/stop-command.mjs' },
27	  { event: 'PreToolUse', matcher: 'Bash', command: 'node $CLAUDE_PROJECT_DIR/.claudinite/shared/engine/hooks/pretooluse-command.mjs' },
28	];
29	
30	export const SCHEDULER_WORKFLOW = '.github/workflows/claudinite-scheduler.yml';
31	export const SETTINGS_PATH = '.claude/settings.json';
32	export const CLAUDE_MD = 'CLAUDE.md';
33	
34	// The retired corpus-index import (#385): a line importing `.claudinite/shared/CLAUDE.md`.
35	// The whole line (and its trailing newline) is removed wherever it appears.
36	const CORPUS_IMPORT_RE = /^.*@\.claudinite\/shared\/CLAUDE\.md.*\n?/m;
37	
38	// Re-converge the scheduler workflow to the vendored stub, with the cron minute set
39	// to this repo's stable hashed value (never guessed — hash-minute.mjs, a pure
40	// function of the full name, so re-vendors and this convergence agree). `stubText`
41	// is the vendored stub's content (the caller reads it from the mount). Returns true
42	// when the file was written (absent, or drifted from the target).
43	export function convergeSchedulerWorkflow(root, fullName, stubText) {
44	  const target = stubText.replace(/cron:\s*'[^']*'/, `cron: '${hashedCron(fullName)}'`);
45	  const path = join(root, SCHEDULER_WORKFLOW);
46	  const current = existsSync(path) ? readFileSync(path, 'utf8') : null;
47	  if (current === target) return false;
48	  mkdirSync(dirname(path), { recursive: true });
49	  writeFileSync(path, target);
50	  return true;
51	}
52	
53	// Ensure the required settings hooks are present (add-if-missing, never clobber).
54	// Returns { added: [labels], error? }. A malformed settings file is reported, never
55	// overwritten (the transactional stance — surface it, don't destroy hand config).
56	export function ensureHooks(root) {
57	  const path = join(root, SETTINGS_PATH);
58	  let settings = {};
59	  if (existsSync(path)) {
60	    try { settings = JSON.parse(readFileSync(path, 'utf8')); }
61	    catch { return { added: [], error: `${SETTINGS_PATH} is not valid JSON — left untouched` }; }
62	  }
63	  settings.hooks ??= {};
64	  const added = [];
65	  for (const h of REQUIRED_HOOKS) {
66	    const list = (settings.hooks[h.event] ??= []);
67	    const present = list.some((group) =>
68	      (h.matcher == null || group.matcher === h.matcher)
69	      && (group.hooks ?? []).some((entry) => entry?.command === h.command));
70	    if (!present) {
71	      list.push({ ...(h.matcher != null ? { matcher: h.matcher } : {}), hooks: [{ type: 'command', command: h.command }] });
72	      added.push(`${h.event}${h.matcher ? `[${h.matcher}]` : ''}`);
73	    }
74	  }
75	  if (added.length) {
76	    mkdirSync(dirname(path), { recursive: true });
77	    writeFileSync(path, JSON.stringify(settings, null, 2) + '\n');
78	  }
79	  return { added };
80	}
81	
82	// Remove the retired `@.claudinite/shared/CLAUDE.md` corpus-index import (#385) from
83	// the repo's CLAUDE.md. Returns true when a line was removed.
84	export function removeRetiredCorpusImport(root) {
85	  const path = join(root, CLAUDE_MD);
86	  if (!existsSync(path)) return false;
87	  const text = readFileSync(path, 'utf8');
88	  if (!CORPUS_IMPORT_RE.test(text)) return false;
89	  writeFileSync(path, text.replace(CORPUS_IMPORT_RE, ''));
90	  return true;
91	}
92	
93	// Converge every wiring surface, returning a flat summary of what changed (empty
94	// when the repo was already converged). `stubText` is the vendored scheduler stub.
95	export function convergeWiring(root, fullName, stubText) {
96	  const changed = [];
97	  if (convergeSchedulerWorkflow(root, fullName, stubText)) changed.push(SCHEDULER_WORKFLOW);
98	  const hooks = ensureHooks(root);
99	  for (const h of hooks.added) changed.push(`hook:${h}`);
100	  if (removeRetiredCorpusImport(root)) changed.push(`removed retired ${CLAUDE_MD} corpus import`);
101	  return { changed, ...(hooks.error ? { error: hooks.error } : {}) };
102	}
103	
104	// CLI: `node converge-wiring.mjs [owner/repo]` — converge THIS repo's wiring. The
105	// full name comes from argv or GITHUB_REPOSITORY/CLAUDINITE_REPO; the scheduler
106	// stub from the vendored mount. This is the single surface bootstrap (Part 6) and
107	// baselining both invoke, so the wiring set is defined once, here.
108	async function main() {
109	  const fullName = process.argv[2] || process.env.GITHUB_REPOSITORY || process.env.CLAUDINITE_REPO;
110	  if (!fullName) { console.error('converge-wiring: need owner/repo (argv or GITHUB_REPOSITORY)'); process.exit(1); }
111	  const root = process.env.CLAUDINITE_REPO_ROOT || process.cwd();
112	  const stubPath = join(root, '.claudinite/shared/engine/scheduler/stubs/claudinite-scheduler.yml');
113	  if (!existsSync(stubPath)) { console.error(`converge-wiring: vendored stub not found at ${stubPath}`); process.exit(1); }
114	  const { changed, error } = convergeWiring(root, fullName, readFileSync(stubPath, 'utf8'));
115	  if (error) console.log(`! ${error}`);
116	  console.log(changed.length ? `converge-wiring: ${changed.join(', ')}` : 'converge-wiring: already converged');
117	}
118	
119	if (process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href) main();
