1	import { readdirSync, readFileSync, existsSync } from 'node:fs';
2	import { join, dirname } from 'node:path';
3	import { fileURLToPath } from 'node:url';
4	import { loadPacks, resolveDeclaredPacks, packEntryId, SHARED_SUBDIR } from '../engine/pack_loader/pack-registry.mjs';
5	import { relativeImports, resolveRelative, ENGINE_DIR_ROOTS } from '../engine/checks/helpers/module-imports.mjs';
6	
7	// The vendor-set computation for the vendored mount (DESIGN.md): given a repo's
8	// pack declaration, the minimal corpus file set that repo persists under
9	// SHARED_SUBDIR — canon-relative paths, mirroring exactly what a future
10	// submodule mounted at that same root would place there. Always computed
11	// against the canon tree THIS module ships in — the nightly runs it from the
12	// home checkout, an on-demand refresh from the tree it just fetched — so the
13	// set and the content can never come from different snapshots.
14	const canonRoot = dirname(dirname(fileURLToPath(import.meta.url))); // <canon>/vendoring/ — canon-internal, never vendored (#385)
15	
16	// Re-exported for the writers (the nightly update pass, an on-demand refresh):
17	// the consumer-side root the set materializes under.
18	export { SHARED_SUBDIR };
19	
20	// The engine is discovered structurally, never listed file-by-file: the engine
21	// root vendors wholesale (a new engine file ships with no edit here). The list
22	// lives in the engine lib (engine/checks/helpers/module-imports.mjs) — the same
23	// surface the pack-independence barrier confines pack imports to, so "what a
24	// pack may import" and "what every consumer carries" can never drift apart —
25	// re-exported here as the vendor-set contract (DESIGN.md). engine/ carries no
26	// tests (they live in engine-tests/, mirroring its structure — #385), so the
27	// engine walk is a plain copy minus *.md — engine docs are canon-maintainer
28	// reference, read upstream when needed, while a pack's .md files are the
29	// payload and ride its directory below (pack tests are still filtered here).
30	export { ENGINE_DIR_ROOTS };
31	
32	const isTest = (name) => name.endsWith('.test.mjs');
33	
34	// The migration machinery a consumer applies from its OWN mount (agent-preprocessing
35	// DESIGN §7): the applier + registry + the note records, so baselining reads the
36	// notes locally and needs no canon checkout in session. NOT the fleet-only drivers
37	// (fleet-apply/fleet-retire, which read the fleet) or the README. Vendoring these
38	// also activates `migrationActive()` legacy-tolerance in consumer checks — inert
39	// until now because no mount migrations existed — which is the intended fleet-wide
40	// behaviour of that gate (a check tolerates a legacy shape while its migration is
41	// live), not a regression.
42	const MIGRATIONS_ROOT = 'migrations';
43	const VENDORED_MIGRATION_MODULES = ['apply.mjs', 'registry.mjs'];
44	function walkMigrations(files, errors) {
45	  for (const name of VENDORED_MIGRATION_MODULES) {
46	    if (existsSync(join(canonRoot, MIGRATIONS_ROOT, name))) files.add(`${MIGRATIONS_ROOT}/${name}`);
47	    else errors.push({ what: `${MIGRATIONS_ROOT}/${name} is missing from the canon tree`, fix: `restore ${MIGRATIONS_ROOT}/${name}` });
48	  }
49	  const recordsDir = `${MIGRATIONS_ROOT}/active_migrations`;
50	  let entries;
51	  try {
52	    entries = readdirSync(join(canonRoot, recordsDir), { withFileTypes: true });
53	  } catch (e) {
54	    errors.push({ what: `${recordsDir} is not a readable directory in the canon tree: ${e.message}`, fix: `restore ${recordsDir}` });
55	    return;
56	  }
57	  for (const entry of entries.sort((a, b) => a.name.localeCompare(b.name))) {
58	    if (entry.isFile() && entry.name.endsWith('.mjs') && !isTest(entry.name)) files.add(`${recordsDir}/${entry.name}`);
59	  }
60	}
61	
62	function walk(relDir, files, errors, { engine = false } = {}) {
63	  let entries;
64	  try {
65	    entries = readdirSync(join(canonRoot, relDir), { withFileTypes: true });
66	  } catch (e) {
67	    errors.push({
68	      what: `${relDir} is not a readable directory in the canon tree: ${e.message}`,
69	      fix: `restore ${relDir}, or fix what names it (an engine root, a pack.mjs skills list)`,
70	    });
71	    return;
72	  }
73	  for (const entry of entries.sort((a, b) => a.name.localeCompare(b.name))) {
74	    if (entry.isDirectory()) {
75	      if (engine && entry.name === 'test') continue;
76	      walk(`${relDir}/${entry.name}`, files, errors, { engine });
77	    } else if (!isTest(entry.name) && !(engine && entry.name.endsWith('.md'))) {
78	      files.add(`${relDir}/${entry.name}`);
79	    }
80	  }
81	}
82	
83	// declaredEntries: the raw `packs` array from .claudinite-checks.json (id
84	// strings and/or entry objects). Returns { files, errors }:
85	// sorted canon-relative paths, and { what, fix } diagnostics. Ids naming no
86	// canon pack (a consumer's local packs, or a typo the runner's settings
87	// validation already flags) are skipped without error; per-user preferences
88	// are deliberately absent — they are never vendored (DESIGN.md). A pack's
89	// bundled skills (<pack>/skills/) ride its directory walk — there is no
90	// separate skills collection to union (#385).
91	export async function computeVendorSet(declaredEntries) {
92	  const files = new Set();
93	  const errors = [];
94	
95	  for (const root of ENGINE_DIR_ROOTS) walk(root, files, errors, { engine: true });
96	  walkMigrations(files, errors);
97	
98	  const packs = await loadPacks();
99	  const byId = new Map(packs.map((p) => [p.id, p]));
100	  const ids = [];
101	  for (const entry of resolveDeclaredPacks(declaredEntries ?? [], packs)) {
102	    const id = packEntryId(entry);
103	    if (id !== undefined && byId.has(id) && !ids.includes(id)) ids.push(id);
104	  }
105	  for (const id of ids) walk(`packs/${id}`, files, errors);
106	
107	  // Coherence guard: the set must be import-closed — every relative import in
108	  // every .mjs it carries resolves to a file it also carries. Structural
109	  // discovery plus the requires closure make that true by construction while
110	  // the corpus honors pack-independence (a pack imports only its own files and
111	  // the engine surface, both always in the set); a violation is canon-side
112	  // breakage, reported here so convergence aborts BEFORE any write (the
113	  // transactional contract) instead of the flipped member crashing on a
114	  // missing module — the failure the gated flip's pilot abort surfaced.
115	  const inSet = new Set(files);
116	  for (const file of inSet) {
117	    if (!file.endsWith('.mjs')) continue;
118	    let src;
119	    try { src = readFileSync(join(canonRoot, file), 'utf8'); } catch { continue; }
120	    for (const { spec } of relativeImports(src)) {
121	      const resolved = resolveRelative(file, spec, (p) => existsSync(join(canonRoot, p)));
122	      if (!resolved) {
123	        errors.push({
124	          what: `${file} imports "${spec}", which resolves to no file in the canon tree`,
125	          fix: 'fix the import specifier, or restore the file it names',
126	        });
127	      } else if (!inSet.has(resolved)) {
128	        errors.push({
129	          what: `${file} imports "${spec}" → ${resolved}, which the vendor set does not carry — a pack imports only its own files and the engine surface (pack-independence)`,
130	          fix: 'fix the import to honor pack-independence (declare the dependency and contribute configuration, or move the helper into checks/lib)',
131	        });
132	      }
133	    }
134	  }
135	
136	  return { files: [...files].sort(), errors };
137	}
