1	// The pre-agent preprocessing stage (agent-preprocessing DESIGN §3). The
2	// scheduler runs a task's declared `agent_preprocessing` command as a SUBPROCESS
3	// before any agent starts — deterministic code work, Action-side, over the one
4	// sanctioned non-MCP surface (the Action GITHUB_TOKEN, inherited in `env`).
5	//
6	// The subprocess is the scheduler's child, so its `agent_preprocessing_timeout`
7	// is a HARD kill: a manual timer SIGKILLs an overrun and the run is reported
8	// failed. Its cwd is the TASK directory, so a declared `node worker.mjs` resolves
9	// to the script beside task.mjs (the containment the contract enforces); the repo
10	// root and slot context are handed in via CLAUDINITE_* env so the worker can act
11	// on the whole repo. Nothing the subprocess prints is threaded into the agent —
12	// preprocessing communicates only through the repository (DESIGN §3).
13	
14	import { spawn } from 'node:child_process';
15	import { existsSync, rmSync } from 'node:fs';
16	import { join } from 'node:path';
17	import { tmpdir } from 'node:os';
18	
19	// Run `command` as a subprocess bounded by `timeoutSeconds`. Resolves (never
20	// rejects) with { ok, timedOut, code, signal, stdout, stderr }: `ok` is a clean
21	// zero exit that did not time out. `taskDir` is the cwd; `env` is the full
22	// environment the child inherits (the caller injects GITHUB_TOKEN + CLAUDINITE_*).
23	export function runPreprocessing(command, { taskDir, env, timeoutSeconds }) {
24	  return new Promise((resolve) => {
25	    const child = spawn(command, { cwd: taskDir, env, shell: true });
26	    let stdout = '';
27	    let stderr = '';
28	    let timedOut = false;
29	    const timer = setTimeout(() => {
30	      timedOut = true;
31	      child.kill('SIGKILL'); // the hard kill — no grace period past the declared bound
32	    }, timeoutSeconds * 1000);
33	
34	    child.stdout?.on('data', (d) => { stdout += d; });
35	    child.stderr?.on('data', (d) => { stderr += d; });
36	    // A spawn error (command not found, etc.) is a failure, not a throw.
37	    child.on('error', (e) => {
38	      clearTimeout(timer);
39	      resolve({ ok: false, timedOut, code: null, signal: null, stdout, stderr: `${stderr}${e.message}` });
40	    });
41	    child.on('close', (code, signal) => {
42	      clearTimeout(timer);
43	      resolve({ ok: code === 0 && !timedOut, timedOut, code, signal, stdout, stderr });
44	    });
45	  });
46	}
47	
48	// The conditional-handoff signal (agent-preprocessing DESIGN §3, E4). A task with
49	// BOTH agent_preprocessing AND a non-`none` agent_model hands off to the agent
50	// ONLY when its worker requests it — so a task can absorb its work into
51	// preprocessing and be AGENTLESS on the quiet nights. The scheduler hands the
52	// worker this path via CLAUDINITE_REQUEST_AGENT and files `ready-for-agent` iff
53	// the worker created it. It is a pure control signal: the worker communicates
54	// DATA to the agent only through the repository, never through this file (DESIGN
55	// §3, "no code→agent data channel").
56	export function agentRequestPath({ pack, task, slotId }) {
57	  return join(tmpdir(), `claudinite-request-agent-${pack}-${task}-${slotId}`);
58	}
59	export function clearAgentRequest(path) { try { rmSync(path, { force: true }); } catch { /* nothing to clear */ } }
60	export function agentRequested(path) { return existsSync(path); }
61	
62	// A one-line reason for the job summary / an issue comment when preprocessing
63	// fails — distinguishing a timeout kill from a non-zero exit.
64	export function preprocessingFailure(result) {
65	  if (result.timedOut) return 'preprocessing exceeded its agent_preprocessing_timeout and was killed';
66	  if (result.code !== null) return `preprocessing exited ${result.code}`;
67	  return `preprocessing could not run: ${result.stderr.trim().split('\n').pop() || 'unknown error'}`;
68	}
