1	import { join, dirname } from 'node:path';
2	import { fileURLToPath, pathToFileURL } from 'node:url';
3	import { MIGRATIONS_SUBDIR, specFiles, migrationActive } from '../engine/checks/helpers/active-migrations.mjs';
4	import { MODEL_FAMILIES } from '../engine/scheduler/model-map.mjs';
5	
6	const dir = dirname(fileURLToPath(import.meta.url));
7	
8	// The migration specs live in a subfolder, so the mechanism (this registry,
9	// apply.mjs, the fleet passes, the README) reads cleanly beside them and the
10	// records are a self-contained set. The sync surface — the subfolder name
11	// (exported so the retire pass can build a record's repo-relative path
12	// migrations/active_migrations/<file>), the spec listing, and
13	// `migrationActive` — lives in the vendored engine lib
14	// (engine/checks/helpers/active-migrations.mjs) because pack CHECKS consult it and packs import
15	// only the engine surface (pack-independence); this registry re-exports it so
16	// canon-side callers keep one import home.
17	export { MIGRATIONS_SUBDIR, migrationActive };
18	const specsDir = join(dir, MIGRATIONS_SUBDIR);
19	
20	// Structural discovery, like packs/ and skills/: every
21	// migrations/active_migrations/<file>.mjs is a migration spec. Each returned object
22	// carries its source `file` (basename) alongside the spec fields, so the retire
23	// pass can name the record to delete.
24	export async function loadMigrations() {
25	  const out = [];
26	  for (const f of specFiles()) {
27	    const spec = (await import(pathToFileURL(join(specsDir, f)).href)).default;
28	    out.push({ file: f, ...spec });
29	  }
30	  return out;
31	}
32	
33	// Read side — "prefer Y, fall back to X": the ordered list of acceptable paths
34	// for a canonical target (canonical first, then its legacy aliases). A tolerance
35	// point consults this instead of hardcoding its own LEGACY_* constant, so a
36	// rename is declared once here and every reader picks it up. Unknown targets
37	// resolve to just themselves.
38	export function resolvePath(migrations, canonical) {
39	  for (const m of migrations) {
40	    for (const a of m.aliases ?? []) {
41	      if (a.canonical === canonical) return [a.canonical, ...(a.legacy ?? [])];
42	    }
43	  }
44	  return [canonical];
45	}
46	
47	// Write side — "and rename X -> Y": for each alias whose legacy path still
48	// exists and whose canonical does not, move legacy -> canonical. `exists` and
49	// `move` are injected so the same logic drives a local checkout (sync fs) or a
50	// future API applier (async). Idempotent — a no-op once the rename is done.
51	export async function applyFileAliases(migration, { exists, move }) {
52	  const moved = [];
53	  for (const a of migration.aliases ?? []) {
54	    for (const legacy of a.legacy ?? []) {
55	      if ((await exists(legacy)) && !(await exists(a.canonical))) {
56	        await move(legacy, a.canonical);
57	        moved.push(`${legacy} -> ${a.canonical}`);
58	      }
59	    }
60	  }
61	  return moved;
62	}
63	
64	// Write side — "vendor these pack templates into the repo": for each declared
65	// materialization {template, dest}, copy the canon template to its destination
66	// when the dest is missing or has drifted from the template (idempotent; a
67	// hand-edited copy self-heals on the next pass). `readTemplate` reads from the
68	// canon (the pack tree / mounted .claudinite), `read`/`write` act on the consumer
69	// repo — the source and destination roots differ in a consumer, so they are
70	// distinct injected readers. Gated by the migration's `appliesTo` so it only
71	// touches repos that ship the pipeline (never the canon repo itself).
72	export async function applyMaterializations(migration, { readTemplate, read, write }) {
73	  if (!migration.materialize?.length) return [];
74	  if (migration.appliesTo && !(await migration.appliesTo(read))) return [];
75	  const done = [];
76	  for (const { template, dest } of migration.materialize) {
77	    const content = await readTemplate(template);
78	    if (content == null) continue; // template missing (partial mount) — skip, never clobber with nothing
79	    if ((await read(dest)) === content) continue; // already vendored, unchanged
80	    await write(dest, content);
81	    done.push(`${dest} <- ${template}`);
82	  }
83	  return done;
84	}
85	
86	// Write side — "rewrite these refs in place": for each declared file, apply its
87	// literal from->to replacements (only those whose `from` is still present),
88	// writing back when anything changed. Idempotent — a no-op once every `from` is
89	// gone. Preserves the rest of the file, so per-repo tweaks the template can't
90	// carry (e.g. an uncommented build_env block) survive. Same `appliesTo` gate.
91	export async function applyRewrites(migration, { read, write }) {
92	  if (!migration.rewrite?.length) return [];
93	  if (migration.appliesTo && !(await migration.appliesTo(read))) return [];
94	  const done = [];
95	  for (const { file, replace } of migration.rewrite) {
96	    const text = await read(file);
97	    if (text == null) continue;
98	    let next = text;
99	    for (const { from, to } of replace ?? []) next = next.split(from).join(to);
100	    if (next !== text) { await write(file, next); done.push(file); }
101	  }
102	  return done;
103	}
104	
105	// A migration record MAY carry a machine-readable AGENTIC note (agent-preprocessing
106	// DESIGN §7, the primitive absorbed from #405): member-side adaptation that no
107	// script can do — adapting consumer-authored `local/packs/` content to a changed
108	// engine contract. Shape: `agentic: { model, instructions }`, model a non-`none`
109	// family. baselining's preprocessing reads this to decide whether a pending note
110	// needs the agent STAGE (and must therefore hold the stamp) rather than converging
111	// in code. Returns the validated note, or null when the record carries none;
112	// throws on a malformed note so a typo fails loudly instead of silently skipping
113	// agentic work (the #405 correctness risk).
114	export function migrationAgentic(m) {
115	  const a = m.agentic;
116	  if (a === undefined || a === null) return null;
117	  if (typeof a !== 'object' || Array.isArray(a)) {
118	    throw new Error(`migration ${m.id}: "agentic" must be an object { model, instructions }`);
119	  }
120	  if (!MODEL_FAMILIES.includes(a.model) || a.model === 'none') {
121	    throw new Error(`migration ${m.id}: agentic.model must be a non-"none" model family (${MODEL_FAMILIES.filter((f) => f !== 'none').join(', ')})`);
122	  }
123	  if (typeof a.instructions !== 'string' || a.instructions.trim() === '') {
124	    throw new Error(`migration ${m.id}: agentic.instructions must be a non-empty string`);
125	  }
126	  return { model: a.model, instructions: a.instructions };
127	}
128	
129	// The records that carry a valid agentic note — the pending set baselining must
130	// escalate to an agent rather than apply in code. Stamp-date filtering (which
131	// notes still apply) is the caller's; this is the agentic gate over that set.
132	export function agenticMigrations(migrations) {
133	  return migrations.filter((m) => migrationAgentic(m) !== null);
134	}
135	
136	// Retirement — the "smart, not overzealous" guard. A migration is retirable only
137	// when the whole fleet is proven done AND has been quiet for a full cycle:
138	//   - the retire pass classified EVERY repo (unknownCount === 0) — an API error
139	//     must not hide a repo still on the legacy shape;
140	//   - ZERO repos still carry its legacy shape (pending.get(id) === 0);
141	//   - the apply pass touched it on NO repo this cycle (appliedThisCycle lacks its
142	//     id) — so the cycle that converges the last member (or crashes mid-apply)
143	//     can never also retire; one guaranteed-quiet apply cycle always separates
144	//     "last application" from "retirement", and a transient false-zero from a
145	//     mid-run crash/delay can't trigger an irreversible delete;
146	//   - it landed strictly before today (>= one nightly cycle old); and
147	//   - it opts into auto-retirement (retire !== 'manual'). A migration whose
148	//     tolerance still lives inline elsewhere sets retire:'manual' so deleting
149	//     this record alone can't strand that tolerance.
150	// YYYY-MM-DD dates compare lexicographically == chronologically. `appliedThisCycle`
151	// is a Set of migration ids the apply pass wrote to >=1 repo this run (empty when
152	// the caller has no apply signal — then only the 0-pending/aged/auto guards apply).
153	export function retirableMigrations(migrations, { pending, unknownCount, today, appliedThisCycle = new Set() }) {
154	  if (unknownCount > 0) return [];
155	  return migrations.filter((m) => {
156	    if ((m.retire ?? 'auto') !== 'auto') return false;
157	    if ((pending.get(m.id) ?? 0) > 0) return false;
158	    if (appliedThisCycle.has(m.id)) return false;
159	    return String(today) > String(m.landed);
160	  });
161	}
162

1	// Namespace local-pack declarations: a repo's own pack (.claudinite/local_packs/<name>/)
2	// is declared in .claudinite-checks.json by its namespaced token `local_packs/<name>`,
3	// not a bare id — self-documenting, and a canon id can never be claimed by accident
4	// (the bare form shared the canon namespace; a collision was only CAUGHT by the
5	// discoverPacks shadow guard, never prevented).
6	//
7	// Seed-style, like grow-with-claudinite-seed: the WRITE rides baselining — its
8	// declaration-normalization step runs in the member checkout (which knows which
9	// declared ids are local packs) and rewrites any bare local-pack declaration to the
10	// namespaced form (see the baselining worker doc). This record holds no ops of its
11	// own; it is the convergence telemetry. The engine accepts BOTH forms throughout (and
12	// after — packEntryId's strip is the permanent parser, not a tolerance this record
13	// carries), so retiring strands nothing.
14	//
15	// legacyPresent: a member still declares a bare id (string entry or entry-object id,
16	// no `local_packs/` prefix) whose pack lives in its own .claudinite/local_packs/ tree.
17	// A bare id with no such local pack is a canon declaration — not this record's business.
18	// retire: 'auto' — self-retires once the fleet has converged and stayed quiet a cycle.
19	export default {
20	  id: 'local-pack-namespace',
21	  landed: '2026-07-19',
22	  summary: 'local-pack declarations namespaced as local_packs/<name> (baselining rewrites bare ids; the engine accepts both forms)',
23	  legacyPresent: async (exists, read) => {
24	    const raw = await read('.claudinite-checks.json');
25	    if (raw == null) return false;
26	    let packs;
27	    try { ({ packs } = JSON.parse(raw)); } catch { return false; }
28	    if (!Array.isArray(packs)) return false;
29	    for (const e of packs) {
30	      const id = typeof e === 'string' ? e : e?.id;
31	      if (typeof id !== 'string' || id.startsWith('local_packs/')) continue;
32	      if (await exists(`.claudinite/local_packs/${id}/pack.mjs`)) return true;
33	    }
34	    return false;
35	  },
36	  retire: 'auto',
37	};
